Creating an admin dashboard for a user management system involves setting up a frontend interface and a backend API to handle user data. Below is a step-by-step guide with code examples using **HTML/CSS/JavaScript** for the frontend and **Node.js/Express** for the backend. This example uses an in-memory database for simplicity.

---

### **1. Project Structure**
```
user-dashboard/
├── backend/
│   ├── server.js
│   └── package.json
├── frontend/
│   ├── index.html
│   └── script.js
```

---

### **2. Backend Setup (Node.js/Express)**

#### **Step 1: Initialize Node.js Project**
```bash
mkdir backend
cd backend
npm init -y
npm install express cors
```

#### **Step 2: `server.js`**
```javascript
const express = require('express');
const cors = require('cors');
const app = express();
const PORT = 3000;

app.use(cors());
app.use(express.json());

// In-memory "database"
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com', role: 'admin' },
  { id: 2, name: 'Bob', email: 'bob@example.com', role: 'user' },
];

// Get all users
app.get('/api/users', (req, res) => {
  res.json(users);
});

// Add a new user
app.post('/api/users', (req, res) => {
  const newUser = { ...req.body, id: users.length + 1 };
  users.push(newUser);
  res.status(201).json(newUser);
});

// Update a user
app.put('/api/users/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const updateUser = req.body;
  users = users.map(user => (user.id === id ? { ...user, ...updateUser } : user));
  res.json(users);
});

// Delete a user
app.delete('/api/users/:id', (req, res) => {
  const id = parseInt(req.params.id);
  users = users.filter(user => user.id !== id);
  res.json(users);
});

app.listen(PORT, () => {
  console.log(`Backend running on http://localhost:${PORT}`);
});
```

---

