---

### **5. Create the Server (`server.js`)**

```javascript
const express = require('express');
const fs = require('fs');
const path = require('path');
const app = express();
const port = 3000;

app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use(express.static('public'));

// Route to handle registration
app.post('/register', (req, res) => {
    const newUser = {
        username: req.body.username,
        email: req.body.email,
        password: req.body.password
    };

    fs.readFile('users.json', 'utf8', (err, data) => {
        if (err) {
            if (err.code === 'ENOENT') {
                // File doesn't exist, create it with an empty array
                fs.writeFile('users.json', JSON.stringify([newUser], null, 2), (err) => {
                    if (err) {
                        console.error(err);
                        return res.status(500).send('Error initializing users file');
                    }
                    res.redirect(`/profile?username=${newUser.username}`);
                });
            } else {
                console.error(err);
                res.status(500).send('Error reading users file');
            }
        } else {
            let users = JSON.parse(data);
            users.push(newUser);
            fs.writeFile('users.json', JSON.stringify(users, null, 2), (err) => {
                if (err) {
                    console.error(err);
                    res.status(500).send('Error writing users file');
                } else {
                    res.redirect(`/profile?username=${newUser.username}`);
                }
            });
        }
    });
});

// API endpoint to fetch user profile
app.get('/api/profile', (req, res) => {
    const username = req.query.username;
    fs.readFile('users.json', 'utf8', (err, data) => {
        if (err) {
            console.error(err);
            res.status(500).send('Error reading users file');
        } else {
            let users = JSON.parse(data);
            const user = users.find(u => u.username === username);
            if (user) {
                res.json(user);
            } else {
                res.status(404).json({ error: 'User not found' });
            }
        }
    });
});

// Serve profile.html
app.get('/profile', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'profile.html'));
});

app.listen(port, () => {
    console.log(`Server running at http://localhost:${port}`);
});
```

---

### **6. Run the Application**

Start the server:

```bash
node server.js
```

Open your browser and navigate to:

- **Register**: `http://localhost:3000/register`
- **Profile**: After registration, you’ll be redirected to `http://localhost:3000/profile?username=your_username`

---

### **Key Features**

- **Registration Form**: Users can input their details.
- **Profile View**: After registration, users can view their profile using a simple API.
- **File-Based Storage**: Uses `users.json` to persist user data.

---

### **Next Steps (Optional Improvements)**

